package com.google.gson.internal.bind;
import com.google.gson.JsonSyntaxException;
import com.google.gson.TypeAdapter;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.internal.JavaVersion;
import com.google.gson.internal.PreJava9DateFormatProvider;
import com.google.gson.internal.bind.util.ISO8601Utils;
import com.google.gson.stream.JsonWriter;
import java.text.DateFormat;
import java.text.ParseException;
import java.text.ParsePosition;
import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.List;
import java.util.Locale;
import java.util.Objects;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.Field;
import java.util.Date;

class DefaultDateTypeAdapterTest {

    private DefaultDateTypeAdapter<Date> adapter;
    private DefaultDateTypeAdapter.DateType<Date> dateType;

    @BeforeEach
    void setUp() throws Exception {
        dateType = mock(DefaultDateTypeAdapter.DateType.class);

        // Use reflection to invoke the private constructor
        var constructor = DefaultDateTypeAdapter.class.getDeclaredConstructor(DefaultDateTypeAdapter.DateType.class, String.class);
        constructor.setAccessible(true);
        adapter = (DefaultDateTypeAdapter<Date>) constructor.newInstance(dateType, "yyyy-MM-dd");
    }

    @Test
    void testRead_NullToken() throws IOException {
        JsonReader jsonReader = mock(JsonReader.class);
        when(jsonReader.peek()).thenReturn(JsonToken.NULL);

        doNothing().when(jsonReader).nextNull();

        Date result = adapter.read(jsonReader);

        verify(jsonReader).peek();
        verify(jsonReader).nextNull();
        assertNull(result);
    }

    @Test
    void testRead_ValidDate() throws IOException {
        JsonReader jsonReader = mock(JsonReader.class);
        when(jsonReader.peek()).thenReturn(JsonToken.STRING);

        // Spy the adapter
        DefaultDateTypeAdapter<Date> spyAdapter = Mockito.spy(adapter);

        // Use reflection to access private method deserializeToDate
        try {
            var method = DefaultDateTypeAdapter.class.getDeclaredMethod("deserializeToDate", JsonReader.class);
            method.setAccessible(true);

            Date expectedDate = new Date();

            // Mock deserializeToDate to return expectedDate
            doReturn(expectedDate).when(spyAdapter).read(any());
            // But we want to test read(), so instead we mock deserializeToDate via reflection:
            // Since Mockito cannot mock private methods, we override it by subclassing
            // Instead, we simulate by temporarily replacing dateType.deserialize to return expectedDate

            when(dateType.deserialize(expectedDate)).thenReturn(expectedDate);

            // Instead of mocking private method, call real read but mock dateType.deserialize
            // So call read on spyAdapter with jsonReader returning STRING token
            // but deserializeToDate will run real method, which tries to parse jsonReader, so we mock jsonReader accordingly

            // To avoid complexity, we invoke the private method directly via reflection here:
            Date deserialized = (Date) method.invoke(spyAdapter, jsonReader);
            when(spyAdapter.read(jsonReader)).thenCallRealMethod();

            // Now call read()
            Date result = spyAdapter.read(jsonReader);

            verify(jsonReader).peek();
            verify(dateType).deserialize(deserialized);
            assertEquals(deserialized, result);

        } catch (Exception e) {
            fail("Reflection failed: " + e.getMessage());
        }
    }
}
